I don't know if this is 100% equivalent to `InitializeCriticalSection`... if that is the cause of this it may be slightly better to do something like this:

```
struct pthread_mutex {
   pthread_spinlock_t initializer_spin_lock;
   BOOL initialized;
   CRITICAL_SECTION cs;
}
#define PTHREAD_MUTEX_INITIALIZER {PTHREAD_SPINLOCK_INITIALIZER, 0, {0}}

static void ensure_mutex_init(pthread_mutex *m) {
   if (m->initialized) return;
   pthread_spin_lock(&m->initializer_spin_lock);
   if (!m->initialized) {
      InitializeCriticalSection(&m->cs);
      m->initialized = 1;
   }
   pthread_spin_unlock(&m->initializer_spin_lock);
}
```

and then make sure that we're calling `ensure_mutex_init` in each of the `pthread_mutex_XXX` functions.

